-- Kisah person index — 25 Nabi (the prophets named in the Qur'an), in the
-- standard chronological order taught across the Muslim world. Three already
-- have a full multi-episode series in `stories` (Yusuf, Musa, Nuh) and link
-- straight to it; the rest get a complete one-page profile so no name is a
-- dead end. Written from established, universally-taught Islamic knowledge —
-- not copied from any single book.

INSERT OR IGNORE INTO kisah_person (slug, category_slug, name_id, name_ar, title_id, summary_id, full_story_slug, sort_order) VALUES
('adam', 'kisah-para-nabi', 'Nabi Adam', 'آدَم عَلَيْهِ السَّلَام', 'Manusia & Nabi Pertama',
 'Adam AS adalah manusia pertama sekaligus nabi pertama yang diciptakan Allah langsung dari tanah, lalu ditiupkan ruh dan diajarkan nama-nama segala sesuatu — keutamaan yang membuat para malaikat diperintah bersujud hormat kepadanya. Ia dan istrinya, Hawa, ditempatkan di surga namun tergoda bisikan Iblis untuk mendekati pohon terlarang, sehingga keduanya diturunkan ke bumi. Kisah Adam ditutup bukan dengan penyesalan tanpa akhir, melainkan dengan taubat yang diterima Allah — menjadikannya teladan pertama tentang kesalahan manusia dan pintu ampunan yang selalu terbuka. Kisahnya banyak disebut dalam Surah Al-Baqarah dan Surah Al-A''raf.', NULL, 1),
('idris', 'kisah-para-nabi', 'Nabi Idris', 'إِدْرِيس عَلَيْهِ السَّلَام', 'Nabi Sebelum Nuh',
 'Idris AS dikenal sebagai nabi yang hidup jauh sebelum Nabi Nuh, disebut Al-Qur''an sebagai sosok yang jujur dan berkedudukan tinggi (Surah Maryam). Tradisi keilmuan Islam menghubungkannya dengan permulaan ilmu tulis-menulis dan hikmah, menjadikannya simbol keteguhan iman yang dipadukan dengan kecintaan pada ilmu. Ia digambarkan sebagai hamba yang sabar dan senantiasa bersyukur di tengah zaman yang jauh dari petunjuk.', NULL, 2),
('nuh', 'kisah-para-nabi', 'Nabi Nuh', 'نُوح عَلَيْهِ السَّلَام', 'Nabi Bahtera & Banjir Besar',
 'Nuh AS berdakwah kepada kaumnya selama ratusan tahun dengan penuh kesabaran, namun hanya sedikit yang beriman — termasuk bukan anaknya sendiri. Atas perintah Allah ia membangun bahtera raksasa yang menyelamatkan orang-orang beriman dan sepasang setiap makhluk dari banjir besar yang menenggelamkan kaum yang ingkar. Kisahnya menjadi teladan abadi tentang kesabaran seorang dai menghadapi penolakan yang panjang.', 'kisah-nuh-01-diutus-dan-ditolak', 3),
('hud', 'kisah-para-nabi', 'Nabi Hud', 'هُود عَلَيْهِ السَّلَام', 'Nabi Kaum ''Ad',
 'Hud AS diutus kepada kaum ''Ad, bangsa yang dikenal kuat secara fisik dan pembangun bangunan megah, namun sombong dan menyembah berhala. Ketika mereka terus mendustakannya, Allah membinasakan mereka dengan angin dahsyat yang menerpa selama berhari-hari, sementara Hud dan orang-orang beriman diselamatkan. Kisahnya diceritakan secara khusus dalam Surah Hud dan Surah Al-Ahqaf sebagai peringatan atas kesombongan kekuatan duniawi.', NULL, 4),
('saleh', 'kisah-para-nabi', 'Nabi Saleh', 'صَالِح عَلَيْهِ السَّلَام', 'Nabi Kaum Tsamud & Unta Betina',
 'Saleh AS diutus kepada kaum Tsamud yang ahli memahat rumah dari gunung batu. Sebagai bukti kenabiannya, Allah mengeluarkan seekor unta betina dari batu sebagai tanda mukjizat, dengan perintah agar kaum itu tidak mengganggunya. Ketika unta itu dibunuh secara zalim, azab Allah berupa suara keras yang menggetarkan bumi membinasakan mereka dalam semalam, sementara Saleh dan pengikutnya selamat.', NULL, 5),
('ibrahim', 'kisah-para-nabi', 'Nabi Ibrahim', 'إِبْرَاهِيم عَلَيْهِ السَّلَام', 'Bapak Para Nabi & Khalilullah',
 'Ibrahim AS dikenal sebagai "Khalilullah" (kekasih Allah) dan bapak dari garis keturunan para nabi setelahnya. Ia mencari kebenaran tentang Tuhan sejak muda hingga menemukan tauhid yang murni, lalu dilemparkan ke dalam api oleh kaumnya karena menghancurkan berhala-berhala — namun Allah menjadikan api itu dingin dan menyelamatkannya. Bersama putranya Ismail, ia membangun Ka''bah di Makkah, dan ujian terbesarnya — kesediaannya menyembelih putranya atas perintah Allah — diabadikan setiap tahun dalam ibadah kurban. Kisahnya tersebar luas di banyak surah, terutama Al-Baqarah, Al-An''am, dan Ash-Shaffat.', NULL, 6),
('luth', 'kisah-para-nabi', 'Nabi Luth', 'لُوط عَلَيْهِ السَّلَام', 'Nabi Kaum Sodom',
 'Luth AS, keponakan Nabi Ibrahim, diutus kepada penduduk kota yang terjerumus dalam perbuatan keji yang belum pernah dilakukan bangsa mana pun sebelumnya. Ia berdakwah dengan gigih namun kaumnya terus menentang, bahkan mengusirnya. Ketika azab datang, kota itu dibalikkan dan dihujani batu, sedangkan Luth beserta keluarganya yang beriman diselamatkan — kecuali istrinya yang turut binasa karena mendustakannya.', NULL, 7),
('ismail', 'kisah-para-nabi', 'Nabi Ismail', 'إِسْمَاعِيل عَلَيْهِ السَّلَام', 'Putra Ibrahim & Leluhur Bangsa Arab',
 'Ismail AS adalah putra sulung Nabi Ibrahim dari Siti Hajar, yang sejak kecil ditinggalkan di lembah tandus Makkah dan diselamatkan lewat munculnya mata air Zamzam. Ia tumbuh menjadi nabi yang taat, bahkan bersedia dengan penuh keikhlasan ketika ayahnya menyampaikan perintah penyembelihan sebagai ujian dari Allah. Bersama Ibrahim, ia turut membangun Ka''bah dan menjadi leluhur dari garis keturunan yang kelak melahirkan Nabi Muhammad ﷺ.', NULL, 8),
('ishaq', 'kisah-para-nabi', 'Nabi Ishaq', 'إِسْحَاق عَلَيْهِ السَّلَام', 'Putra Ibrahim, Ayah Ya''qub',
 'Ishaq AS adalah putra Nabi Ibrahim dari Sarah, lahir sebagai kabar gembira yang disampaikan malaikat di usia orang tuanya yang telah lanjut. Ia meneruskan dakwah tauhid ayahnya dan menjadi ayah dari Nabi Ya''qub, sehingga garis kenabian bani Israil bersambung melaluinya. Al-Qur''an menyebutnya sebagai nabi yang saleh dan diberkahi bersama keturunannya.', NULL, 9),
('yaqub', 'kisah-para-nabi', 'Nabi Ya''qub', 'يَعْقُوب عَلَيْهِ السَّلَام', 'Ayah dari Nabi Yusuf',
 'Ya''qub AS, putra Ishaq, adalah ayah dari dua belas putra yang salah satunya adalah Nabi Yusuf. Ia mengalami ujian panjang berupa perpisahan dengan Yusuf yang membuatnya menangis hingga matanya memutih karena kesedihan, namun tetap berbaik sangka kepada Allah. Kisahnya menyatu erat dengan kisah Nabi Yusuf dalam Surah Yusuf sebagai teladan kesabaran seorang ayah.', 'kisah-nabi-yusuf-01-mimpi', 10),
('yusuf', 'kisah-para-nabi', 'Nabi Yusuf', 'يُوسُف عَلَيْهِ السَّلَام', 'Kisah Terindah dalam Al-Qur''an',
 'Yusuf AS mengalami perjalanan hidup yang penuh ujian: dibuang saudara-saudaranya ke dalam sumur, dijual sebagai budak, difitnah di rumah seorang pembesar Mesir, dipenjara bertahun-tahun tanpa bersalah, hingga akhirnya diangkat menjadi pejabat tinggi Mesir yang menyelamatkan negeri itu dari kelaparan. Kisahnya, yang Allah sebut sebagai "sebaik-baik kisah" dalam Surah Yusuf, mengajarkan kesabaran, kejujuran, dan pengampunan — puncaknya ketika Yusuf memaafkan saudara-saudaranya yang dahulu mencelakainya.', 'kisah-nabi-yusuf-01-mimpi', 11),
('ayyub', 'kisah-para-nabi', 'Nabi Ayyub', 'أَيُّوب عَلَيْهِ السَّلَام', 'Teladan Kesabaran dalam Ujian',
 'Ayyub AS dikenal sebagai simbol kesabaran tertinggi: seorang yang kaya raya dan sehat kehilangan harta, anak-anak, dan kesehatannya dalam ujian yang bertahun-tahun, namun tak pernah henti bersyukur dan berdoa kepada Allah dengan penuh adab. Doanya yang lembut — memohon kesembuhan tanpa mengeluh — dikabulkan, dan Allah mengembalikan seluruh yang hilang berlipat ganda. Kisahnya diabadikan dalam Surah Al-Anbiya dan Surah Shad.', NULL, 12),
('syuaib', 'kisah-para-nabi', 'Nabi Syu''aib', 'شُعَيْب عَلَيْهِ السَّلَام', 'Nabi Penduduk Madyan',
 'Syu''aib AS diutus kepada penduduk Madyan yang terkenal curang dalam timbangan dan takaran perniagaan. Ia menyerukan tauhid sekaligus kejujuran dalam bermuamalah, namun kaumnya menolak dan mengancamnya. Azab berupa gempa dan suara keras menimpa mereka, sementara Syu''aib dan pengikutnya yang beriman diselamatkan — menjadikannya teladan penting tentang keterkaitan iman dengan etika perniagaan.', NULL, 13),
('musa', 'kisah-para-nabi', 'Nabi Musa', 'مُوسَى عَلَيْهِ السَّلَام', 'Kalimullah, Nabi Bani Israil',
 'Musa AS diselamatkan sejak bayi dari pembantaian Fir''aun dengan dihanyutkan di sungai Nil, lalu tumbuh di istana Fir''aun sendiri sebelum akhirnya diutus kembali kepadanya sebagai nabi untuk membebaskan Bani Israil. Ia berbicara langsung dengan Allah (karena itu digelari Kalimullah), membelah lautan dengan tongkatnya, dan menerima Taurat di Bukit Sinai. Kisahnya adalah yang paling banyak disebut dalam Al-Qur''an, menggambarkan perjuangan panjang menegakkan tauhid melawan kezaliman.', 'kisah-nabi-musa-01-kelahiran', 14),
('harun', 'kisah-para-nabi', 'Nabi Harun', 'هَارُون عَلَيْهِ السَّلَام', 'Saudara & Pendamping Nabi Musa',
 'Harun AS adalah saudara kandung Nabi Musa yang diutus mendampinginya berdakwah kepada Fir''aun, karena Musa memohon kefasihan lisan Harun sebagai penguat dakwahnya. Ia dipercaya memimpin Bani Israil saat Musa munajat di Bukit Sinai, dan berusaha keras mencegah mereka menyembah patung anak sapi meski akhirnya sebagian tetap tersesat. Kisahnya menunjukkan pentingnya dukungan dan kerja sama dalam mengemban dakwah.', NULL, 15),
('dzulkifli', 'kisah-para-nabi', 'Nabi Dzulkifli', 'ذُو الْكِفْل عَلَيْهِ السَّلَام', 'Nabi yang Sabar & Teguh Janji',
 'Dzulkifli AS disebut Al-Qur''an bersama Ismail dan Idris sebagai golongan orang-orang yang sabar (Surah Al-Anbiya). Namanya, yang berarti "pemilik/penepat janji", dikaitkan dengan riwayat bahwa ia berjanji untuk senantiasa berpuasa di siang hari, shalat malam, dan tidak marah, lalu menepatinya secara konsisten. Ia menjadi teladan keistiqamahan dalam ibadah dan akhlak.', NULL, 16),
('daud', 'kisah-para-nabi', 'Nabi Daud', 'دَاوُد عَلَيْهِ السَّلَام', 'Raja & Nabi, Pemilik Kitab Zabur',
 'Daud AS mengawali kisahnya sebagai pemuda pemberani yang mengalahkan raksasa Jalut, lalu diangkat Allah menjadi raja sekaligus nabi bagi Bani Israil. Ia dianugerahi suara merdu yang membuat gunung-gunung dan burung ikut bertasbih bersamanya, kemahiran melunakkan besi untuk membuat baju besi, serta Kitab Zabur. Kisahnya mengajarkan keseimbangan antara kekuasaan duniawi dan kedekatan dengan Allah.', NULL, 17),
('sulaiman', 'kisah-para-nabi', 'Nabi Sulaiman', 'سُلَيْمَان عَلَيْهِ السَّلَام', 'Raja Para Nabi, Penguasa Jin & Angin',
 'Sulaiman AS, putra Nabi Daud, dianugerahi kerajaan yang tak tertandingi: mampu memahami bahasa binatang, menguasai angin dan jin, serta memimpin pasukan dari berbagai makhluk. Kisahnya dengan Ratu Balqis dari negeri Saba — yang berakhir dengan keislaman sang ratu — menjadi salah satu narasi paling terkenal dalam Surah An-Naml. Meski memiliki kekuasaan luar biasa, ia dikenal rendah hati dan senantiasa bersyukur kepada Allah.', NULL, 18),
('ilyas', 'kisah-para-nabi', 'Nabi Ilyas', 'إِلْيَاس عَلَيْهِ السَّلَام', 'Nabi Penentang Penyembahan Ba''al',
 'Ilyas AS diutus kepada Bani Israil yang saat itu menyembah berhala bernama Ba''al. Ia menyerukan mereka kembali kepada tauhid dengan penuh keberanian meski menghadapi penolakan keras dari penguasa dan masyarakatnya. Al-Qur''an menempatkannya sejajar dengan nabi-nabi saleh lainnya dalam Surah Ash-Shaffat sebagai teladan keteguhan melawan kemusyrikan yang mengakar.', NULL, 19),
('ilyasa', 'kisah-para-nabi', 'Nabi Ilyasa''', 'الْيَسَع عَلَيْهِ السَّلَام', 'Penerus Dakwah Nabi Ilyas',
 'Ilyasa'' AS meneruskan dakwah Nabi Ilyas kepada Bani Israil setelahnya, mengajak mereka kembali kepada jalan yang lurus. Al-Qur''an menyebut namanya bersama para nabi pilihan lain sebagai orang-orang yang termasuk golongan terbaik (Surah Shad dan Al-An''am), meski riwayat rinci tentang perjalanan dakwahnya tidak banyak dijelaskan secara mendetail.', NULL, 20),
('yunus', 'kisah-para-nabi', 'Nabi Yunus', 'يُونُس عَلَيْهِ السَّلَام', 'Nabi yang Ditelan Ikan Besar',
 'Yunus AS meninggalkan kaumnya di Ninawa dalam keadaan marah sebelum turunnya izin Allah, lalu ia menaiki kapal yang terancam tenggelam sehingga ia dilempar ke laut dan ditelan ikan besar. Di dalam kegelapan tiga lapis — perut ikan, lautan, dan malam — ia berdoa dengan kalimat masyhur "Laa ilaaha illa Anta, subhaanaka, innii kuntu minazh-zhaalimiin", dan Allah menyelamatkannya. Kaumnya yang ditinggalkan justru kemudian beriman seluruhnya, menjadikannya satu-satunya kaum nabi yang azabnya diangkat setelah beriman.', NULL, 21),
('zakaria', 'kisah-para-nabi', 'Nabi Zakaria', 'زَكَرِيَّا عَلَيْهِ السَّلَام', 'Ayah Nabi Yahya, Pengasuh Maryam',
 'Zakaria AS adalah nabi yang mengasuh Maryam binti Imran di mihrab dan senantiasa mendapati rezeki tak terduga di sisinya. Di usia tua dan istrinya yang mandul, ia berdoa penuh harap memohon keturunan, dan Allah mengabulkannya dengan kelahiran Nabi Yahya sebagai kabar gembira. Kisahnya dalam Surah Maryam mengajarkan agar tak pernah putus asa dari rahmat Allah meski secara logika mustahil.', NULL, 22),
('yahya', 'kisah-para-nabi', 'Nabi Yahya', 'يَحْيَى عَلَيْهِ السَّلَام', 'Putra Zakaria, Nabi Sejak Kecil',
 'Yahya AS dianugerahi hikmah dan kenabian sejak masih kanak-kanak, serta dikenal sangat tekun beribadah, penyayang kepada orang tuanya, dan jauh dari kesombongan. Al-Qur''an memberinya penghormatan "salaamun ''alaihi" pada hari lahir, wafat, dan hari kebangkitannya kelak (Surah Maryam) — kehormatan yang juga disematkan kepada sepupunya, Nabi Isa.', NULL, 23),
('isa', 'kisah-para-nabi', 'Nabi Isa', 'عِيسَى عَلَيْهِ السَّلَام', 'Putra Maryam, Nabi Terakhir Bani Israil',
 'Isa AS dilahirkan secara mukjizat dari Maryam tanpa ayah, sebagai tanda kekuasaan Allah. Sejak bayi ia telah berbicara membela kesucian ibunya, lalu tumbuh menjadi nabi yang diberi mukjizat menyembuhkan penyakit dan menghidupkan yang mati dengan izin Allah. Dalam akidah Islam, ia tidak disalib maupun mati, melainkan diangkat oleh Allah ke langit, dan akan turun kembali di akhir zaman sebagai bagian dari tanda-tanda hari kiamat.', NULL, 24),
('muhammad', 'kisah-para-nabi', 'Nabi Muhammad ﷺ', 'مُحَمَّد صَلَّى اللهُ عَلَيْهِ وَسَلَّم', 'Nabi & Rasul Terakhir, Rahmat bagi Semesta',
 'Muhammad ﷺ lahir di Makkah dan menjadi yatim piatu sejak kecil, tumbuh dengan akhlak mulia yang membuatnya dijuluki Al-Amin (yang tepercaya) jauh sebelum kenabian. Di usia 40 tahun ia menerima wahyu pertama di Gua Hira, lalu berdakwah selama 23 tahun — 13 tahun di Makkah menghadapi penolakan keras, dan 10 tahun di Madinah membangun masyarakat yang berlandaskan Al-Qur''an dan Sunnah. Ia wafat sebagai nabi dan rasul terakhir, meninggalkan Al-Qur''an dan teladan hidupnya sebagai pedoman abadi bagi seluruh umat manusia hingga akhir zaman.', NULL, 25);
